	private static Set<String> duplicateInsensitiveDistinctCountVars(Group group) {
		if (group == null || !group.getGroupBindingNames().isEmpty() || group.getGroupElements().isEmpty()) {
			return Set.of();
		}
		Set<String> vars = new LinkedHashSet<>();
		for (GroupElem groupElement : group.getGroupElements()) {
			AggregateOperator operator = groupElement.getOperator();
			if (!(operator instanceof Count count) || !count.isDistinct()
					|| !(count.getArg()instanceof Var var) || var.hasValue() || var.getName() == null) {
				return Set.of();
			}
			vars.add(var.getName());
		}
		return vars.isEmpty() ? Set.of() : Set.copyOf(vars);
	}

	private static boolean isAskRootSlice(TupleExpr tupleExpr) {
		return tupleExpr instanceof Slice slice && isAskRootSlice(slice);
	}

	private static boolean isAskRootSlice(Slice slice) {
		return !slice.hasOffset() && slice.hasLimit() && slice.getLimit() == 1L;
	}

	private static boolean canRemoveTopLevelAskOptional(LeftJoin leftJoin) {
		return !leftJoin.hasCondition() && hasSafeStructuralFingerprint(leftJoin.getLeftArg())
				&& hasSafeStructuralFingerprint(leftJoin.getRightArg());
	}

	private static boolean samePureSubtree(TupleExpr left, TupleExpr right) {
		return left.equals(right) && hasSafeStructuralFingerprint(left) && hasSafeStructuralFingerprint(right);
	}

	private static boolean hasAssuredResultBinding(TupleExpr tupleExpr) {
		if (tupleExpr instanceof StatementPattern statementPattern) {
			return isResultBinding(statementPattern.getSubjectVar())
					|| isResultBinding(statementPattern.getPredicateVar())
					|| isResultBinding(statementPattern.getObjectVar())
					|| isResultBinding(statementPattern.getContextVar());
		}
		if (tupleExpr instanceof BindingSetAssignment assignment) {
			return everyAssignmentRowHasResultBinding(assignment);
		}
		if (tupleExpr instanceof Join join) {
			return hasAssuredResultBinding(join.getLeftArg()) || hasAssuredResultBinding(join.getRightArg());
		}
		if (tupleExpr instanceof Union union) {
			return hasAssuredResultBinding(union.getLeftArg()) && hasAssuredResultBinding(union.getRightArg());
		}
		if (tupleExpr instanceof Difference difference) {
			return hasAssuredResultBinding(difference.getLeftArg());
		}
		if (tupleExpr instanceof LeftJoin leftJoin) {
			return hasAssuredResultBinding(leftJoin.getLeftArg());
		}
		return false;
	}

	private static boolean everyAssignmentRowHasResultBinding(BindingSetAssignment assignment) {
		boolean sawRow = false;
		for (BindingSet bindingSet : assignment.getBindingSets()) {
			sawRow = true;
			if (bindingSet.getBindingNames().isEmpty()) {
				return false;
			}
		}
		return sawRow;
	}

	private static boolean isResultBinding(Var var) {
		return var != null && !var.isConstant();
	}

	private static boolean hasSafeStructuralFingerprint(TupleExpr tupleExpr) {
		if (tupleExpr instanceof StatementPattern || tupleExpr instanceof BindingSetAssignment
				|| tupleExpr instanceof SingletonSet || tupleExpr instanceof EmptySet) {
			return true;
		}
		if (tupleExpr instanceof Join join) {
			return hasSafeStructuralFingerprint(join.getLeftArg()) && hasSafeStructuralFingerprint(join.getRightArg());
		}
		if (tupleExpr instanceof Union union) {
			return hasSafeStructuralFingerprint(union.getLeftArg())
					&& hasSafeStructuralFingerprint(union.getRightArg());
		}
		if (tupleExpr instanceof Difference difference) {
			return hasSafeStructuralFingerprint(difference.getLeftArg())
					&& hasSafeStructuralFingerprint(difference.getRightArg());
		}
		if (tupleExpr instanceof LeftJoin leftJoin) {
			return !leftJoin.hasCondition() && hasSafeStructuralFingerprint(leftJoin.getLeftArg())
					&& hasSafeStructuralFingerprint(leftJoin.getRightArg());
		}
		return false;
	}
